# app.py
from flask import Flask, request, jsonify, render_template
import boto3
import os
import uuid
from selenium import webdriver
from selenium.webdriver.chrome.service import Service
from selenium.webdriver.chrome.options import Options
from webdriver_manager.chrome import ChromeDriverManager
import logging

app = Flask(__name__)

# Configure logging
logging.basicConfig(level=logging.INFO)
logger = logging.getLogger(__name__)

# AWS S3 Configuration
S3_BUCKET_NAME = os.environ.get('S3_BUCKET_NAME', 'your-screenshot-bucket') # Replace with your S3 bucket name
AWS_REGION = os.environ.get('AWS_REGION', 'us-east-1') # Replace with your AWS region

s3_client = boto3.client('s3', region_name=AWS_REGION)

# Configure Chrome options for headless execution
def get_chrome_driver():
    chrome_options = Options()
    chrome_options.add_argument("--headless")
    chrome_options.add_argument("--no-sandbox")
    chrome_options.add_argument("--disable-dev-shm-usage")
    chrome_options.add_argument("--window-size=1280,768") # Standard desktop size for screenshots
    chrome_options.add_argument("--hide-scrollbars")
    chrome_options.add_argument("--enable-logging")
    chrome_options.add_argument("--v=1")
    chrome_options.add_argument("--log-level=0") # INFO level
    chrome_options.add_argument("--disable-gpu")
    chrome_options.add_argument("--single-process") # Required for some environments
    chrome_options.add_argument("--disable-web-security") # Allow cross-origin for screenshotting
    
    # Initialize ChromeDriver using webdriver_manager
    service = Service(ChromeDriverManager().install())
    driver = webdriver.Chrome(service=service, options=chrome_options)
    return driver

@app.route('/')
def index():
    return render_template('index.html')

@app.route('/screenshot', methods=['POST'])
def screenshot():
    data = request.json
    if not data or 'url' not in data:
        return jsonify({"error": "Missing 'url' in request body"}), 400

    target_url = data['url']
    logger.info(f"Received request to screenshot: {target_url}")

    if not (target_url.startswith('http://') or target_url.startswith('https://')):
        target_url = 'http://' + target_url # Prepend http:// if missing

    screenshot_filename = f"{uuid.uuid4()}.png"
    temp_filepath = f"/tmp/{screenshot_filename}" # Store locally before uploading to S3

    driver = None
    try:
        driver = get_chrome_driver()
        driver.get(target_url)
        driver.save_screenshot(temp_filepath)
        logger.info(f"Screenshot saved locally to {temp_filepath}")

        # Upload to S3
        s3_client.upload_file(temp_filepath, S3_BUCKET_NAME, screenshot_filename)
        s3_url = f"https://{S3_BUCKET_NAME}.s3.{AWS_REGION}.amazonaws.com/{screenshot_filename}"
        logger.info(f"Screenshot uploaded to S3: {s3_url}")

        return jsonify({
            "url": target_url,
            "screenshot_url": s3_url,
            "filename": screenshot_filename
        }), 200

    except Exception as e:
        logger.error(f"Error generating screenshot for {target_url}: {e}", exc_info=True)
        return jsonify({"error": f"Failed to generate screenshot: {str(e)}"}), 500
    finally:
        if driver:
            driver.quit()
        # Clean up local temporary file
        if os.path.exists(temp_filepath):
            os.remove(temp_filepath)
            logger.info(f"Cleaned up local file: {temp_filepath}")

if __name__ == '__main__':
    # Ensure the /tmp directory exists on EC2 if it's not guaranteed
    os.makedirs('/tmp', exist_ok=True)
    # The port needs to be 80 if running directly as a web server on EC2, or handled by a reverse proxy
    app.run(host='0.0.0.0', port=5000)

